// Package workspace resolves and represents a single aienvs workspace —
// the directory anchored by a `.aienv.yaml` manifest.
//
// Every aienvs invocation operates on exactly one resolved workspace
// (plan decision R1). Multi-workspace isolation (plan decision #22) is
// enforced at the filesystem layer by fsroot: writes from this process
// must stay inside Workspace.Root.
//
// Discovery is cwd-relative by default and follows the user's *logical*
// path (no EvalSymlinks) so a user who `cd`'d through a symlinked
// directory gets the workspace they expect.
package workspace

import (
	"errors"
	"fmt"
	"os"
	"path/filepath"
)

// ManifestName is the literal filename aienvs looks for when walking up
// from cwd. The suffix is singular by design — see docs/spec/manifest-v1.md.
const ManifestName = ".aienv.yaml"

// DefaultMaxHops caps the upward walk. Picked as a safety net against
// unbounded cycles on pathological filesystems (symlink loops,
// overlayfs layering bugs, etc.). Real workspaces are never more than
// a handful of directories deep inside a user's home directory.
const DefaultMaxHops = 64

// Sentinel errors. Callers branch on these with errors.Is.
var (
	// ErrNotFound is returned when no manifest was discovered up to the
	// walk terminus (filesystem root or Options.StopAt).
	ErrNotFound = errors.New("no .aienv.yaml workspace found")

	// ErrMaxWalkExceeded is returned when discovery exceeds
	// Options.MaxHops (or DefaultMaxHops) traversals. This is the v1
	// cycle-safety net; true inode-based cycle detection is deferred
	// per origin R8.
	ErrMaxWalkExceeded = errors.New("workspace discovery exceeded maximum hop limit")

	// ErrInvalidOptions is returned when Options describe a workspace
	// override that does not resolve to a directory containing a
	// manifest.
	ErrInvalidOptions = errors.New("invalid workspace discovery options")
)

// Workspace is the resolved binding of a manifest to a directory.
//
// Fields are populated by Find. A caller holding a *Workspace can
// safely pass Root to fsroot.OpenWorkspaceRoot and use ManifestPath
// with manifest.LoadFile.
type Workspace struct {
	// ManifestPath is the absolute path to the resolved `.aienv.yaml`.
	ManifestPath string

	// Root is the absolute path to the directory containing
	// ManifestPath. This is the boundary fsroot scopes to for any
	// write this process makes inside the workspace.
	Root string

	// LogicalCwd is the cwd Find was given (or the user's actual cwd
	// if none was provided). Preserved for diagnostics; callers should
	// not treat it as authoritative for filesystem containment checks —
	// use Root.
	LogicalCwd string
}

// Options controls discovery. All fields are optional.
type Options struct {
	// Workspace, if non-empty, short-circuits discovery. Accepts either
	// a directory path (expected to contain a `.aienv.yaml`) or the
	// path to a `.aienv.yaml` file directly.
	Workspace string

	// StopAt, if non-empty, terminates the upward walk at this
	// directory. Discovery refuses to look above it. Empty means
	// "filesystem root."
	StopAt string

	// MaxHops caps the upward walk. Zero means DefaultMaxHops.
	MaxHops int
}

// OptionsFromEnv reads AIENVS_WORKSPACE_STOP_AT into Options.StopAt.
// Callers (typically the CLI layer) merge these with flag-derived
// options before calling Find.
func OptionsFromEnv() Options {
	return Options{
		StopAt: os.Getenv("AIENVS_WORKSPACE_STOP_AT"),
	}
}

// Find resolves a workspace from cwd (or the process cwd if cwd == "")
// per the rules documented on Options.
//
// Discovery order:
//  1. If opts.Workspace is set, validate it and short-circuit.
//  2. Otherwise, walk up the logical parent chain from cwd.
//  3. Stop at opts.StopAt (if set), filesystem root, or when a
//     manifest is found.
//  4. Abort with ErrMaxWalkExceeded if the hop budget is exhausted.
func Find(cwd string, opts Options) (*Workspace, error) {
	if cwd == "" {
		c, err := os.Getwd()
		if err != nil {
			return nil, fmt.Errorf("workspace: getwd: %w", err)
		}
		cwd = c
	}
	logical := cwd

	if opts.Workspace != "" {
		return resolveExplicit(opts.Workspace, logical)
	}

	cwdAbs, err := absLogical(cwd)
	if err != nil {
		return nil, fmt.Errorf("workspace: cwd %q: %w", cwd, err)
	}
	stopAbs := ""
	if opts.StopAt != "" {
		s, err := absLogical(opts.StopAt)
		if err != nil {
			return nil, fmt.Errorf("workspace: stop-at %q: %w", opts.StopAt, err)
		}
		stopAbs = s
	}

	budget := opts.MaxHops
	if budget <= 0 {
		budget = DefaultMaxHops
	}

	dir := cwdAbs
	for hops := 0; hops <= budget; hops++ {
		manifest := filepath.Join(dir, ManifestName)
		if ok, err := regularFileExists(manifest); err != nil {
			return nil, fmt.Errorf("workspace: stat %q: %w", manifest, err)
		} else if ok {
			return &Workspace{
				ManifestPath: manifest,
				Root:         dir,
				LogicalCwd:   logical,
			}, nil
		}

		// Terminus: user-supplied stop.
		if stopAbs != "" && dir == stopAbs {
			break
		}

		parent := filepath.Dir(dir)
		if parent == dir {
			// Filesystem root.
			break
		}
		dir = parent
	}

	if dir != "" {
		last := dir
		// Disambiguate hop-limit exhaustion from terminus.
		nextParent := filepath.Dir(last)
		if nextParent != last && (stopAbs == "" || last != stopAbs) {
			return nil, fmt.Errorf("%w: cwd=%q stop-at=%q budget=%d", ErrMaxWalkExceeded, logical, stopAbs, budget)
		}
	}

	return nil, fmt.Errorf("%w: searched from %q", ErrNotFound, logical)
}

func resolveExplicit(path, logical string) (*Workspace, error) {
	abs, err := absLogical(path)
	if err != nil {
		return nil, fmt.Errorf("%w: resolve %q: %w", ErrInvalidOptions, path, err)
	}
	st, err := os.Stat(abs)
	if err != nil {
		return nil, fmt.Errorf("%w: stat %q: %w", ErrInvalidOptions, path, err)
	}

	if st.IsDir() {
		manifest := filepath.Join(abs, ManifestName)
		if ok, err := regularFileExists(manifest); err != nil {
			return nil, fmt.Errorf("%w: stat %q: %w", ErrInvalidOptions, manifest, err)
		} else if !ok {
			return nil, fmt.Errorf("%w: %s not present under %q", ErrInvalidOptions, ManifestName, abs)
		}
		return &Workspace{ManifestPath: manifest, Root: abs, LogicalCwd: logical}, nil
	}

	// Treat as a direct manifest path.
	if filepath.Base(abs) != ManifestName {
		return nil, fmt.Errorf("%w: %q is not a directory nor a %s file", ErrInvalidOptions, path, ManifestName)
	}
	root := filepath.Dir(abs)
	return &Workspace{ManifestPath: abs, Root: root, LogicalCwd: logical}, nil
}

// absLogical returns filepath.Abs(p) without resolving symlinks. For
// consistency, we also clean the path so filepath.Dir walks behave
// predictably.
func absLogical(p string) (string, error) {
	if p == "" {
		return "", fmt.Errorf("empty path")
	}
	if filepath.IsAbs(p) {
		return filepath.Clean(p), nil
	}
	wd, err := os.Getwd()
	if err != nil {
		return "", err
	}
	return filepath.Clean(filepath.Join(wd, p)), nil
}

// regularFileExists returns true iff path resolves (via Lstat, NOT
// EvalSymlinks) to a regular file. Symlinks to regular files count —
// but a symlink to a symlink to a regular file requires a follow,
// which Lstat refuses. For the manifest discovery case, the
// realistic user setup is direct regular files, so we intentionally
// keep the check simple and let fsroot enforce safety at write time.
func regularFileExists(path string) (bool, error) {
	fi, err := os.Stat(path)
	if err != nil {
		if errors.Is(err, os.ErrNotExist) {
			return false, nil
		}
		return false, err
	}
	return fi.Mode().IsRegular(), nil
}

